      level: "advanced",
      tags: ["failure first", "rate limiting", "backpressure"],
      prompt: "A shipping-label partner reduces quota from 1,000 to 100 requests/second. Your queue receives 600 jobs/second, workers retry 429 responses after one second, and orders share the queue with delivery-status polling.",
